const src = $input.first().json;
const body = src.body || src;
const email = (body.email || '').toString().trim().toLowerCase();
const password = (body.password || '').toString();
const token = (body.token || '').toString().trim();
return [{ json: { email, password, token } }];

const rows = $input.all().map(i => i.json);
const prev = $('Code: Parse').first().json;
const { email, password, token } = prev;

if (!rows.length) {
  return [{ json: { ok: false, error: 'Credenciales inválidas' } }];
}

const row = rows[0];

// If logging in with password (not token-only), verify bcrypt
if (!token && password) {
  const bcrypt = require('bcryptjs');
  const valid = bcrypt.compareSync(password, row.password_hash || '');
  if (!valid) {
    return [{ json: { ok: false, error: 'Credenciales inválidas' } }];
  }
}

// If token login (no password provided), trust the token lookup directly
if (!token && !password) {
  return [{ json: { ok: false, error: 'Se requiere token o contraseña' } }];
}

const jwt = require('jsonwebtoken');
const signed = jwt.sign(
  { sub: row.id, role: 'supplier' },
  process.env.JWT_SECRET,
  { expiresIn: '7d' }
);

return [{
  json: {
    ok: true,
    jwt: signed,
    supplier: {
      id: row.id,
      company: row.company,
      email: row.email,
      phone: row.phone,
      nit: row.nit,
      city: row.city,
      dept: row.dept,
      bank_account: row.bank_account,
      platform_fee_pct: row.platform_fee_pct
    }
  }
}];
